class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        ans = 1
        for i in range(1, n):
            if s[i] == s[i - 1]:
                if i - 2 >= 0 and s[i] == s[i - 2]:
                    ans = max(ans, 2)
                else:
                    ans += 1
            else:
                ans += 1
        return ans
```

